public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {
        LoanApprovalSystem sys = new LoanApprovalSystem();

        // ── LoanException is a checked exception ──
        try {
            boolean isChecked = new LoanException("test")
                instanceof Exception;
            checkBool("LoanException extends Exception", true, isChecked);
            boolean notRuntime = !(new LoanException("test")
                instanceof RuntimeException);
            checkBool("LoanException is checked (not RuntimeException)",
                      true, notRuntime);
        } catch (Exception e) { fail("LoanException class check", e); }

        // ── validateLoan: valid application ──
        try {
            check("validate Gru",
                  "Gru approved for $2000000",
                  sys.validateLoan("Gru", 2000000, 9));
        } catch (LoanException e) { fail("validate Gru", e); }

        // ── validateLoan: blank name ──
        try {
            sys.validateLoan("", 50000, 8);
            fail("blank name should throw");
        } catch (LoanException e) {
            check("blank name message", "Villain name required", e.getMessage());
        }

        // ── validateLoan: amount too small ──
        try {
            sys.validateLoan("Gru", 500, 9);
            fail("amount too small should throw");
        } catch (LoanException e) {
            check("amount too small message", "Amount too small", e.getMessage());
        }

        // ── validateLoan: score out of range (low) ──
        try {
            sys.validateLoan("Vector", 50000, 0);
            fail("score 0 should throw");
        } catch (LoanException e) {
            check("score 0 message", "Score must be 1-10", e.getMessage());
        }

        // ── validateLoan: score out of range (high) ──
        try {
            sys.validateLoan("Vector", 50000, 11);
            fail("score 11 should throw");
        } catch (LoanException e) {
            check("score 11 message", "Score must be 1-10", e.getMessage());
        }

        // ── processApplication: approved ──
        check("processApplication approved",
              "Gru approved for $2000000 (done)",
              sys.processApplication("Gru", 2000000, 9));

        // ── processApplication: denied (blank name) ──
        check("processApplication blank name",
              "Denied: Villain name required (done)",
              sys.processApplication("", 50000, 8));

        // ── processApplication: denied (amount too small) ──
        check("processApplication amount too small",
              "Denied: Amount too small (done)",
              sys.processApplication("Minion", 5, 7));

        // ── processApplication: denied (bad score) ──
        check("processApplication bad score",
              "Denied: Score must be 1-10 (done)",
              sys.processApplication("Bob", 10000, 0));

        // ── finally always appends (done) ──
        String r1 = sys.processApplication("Gru", 2000000, 9);
        String r2 = sys.processApplication("", 1000, 5);
        checkBool("finally on success",  true, r1.endsWith("(done)"));
        checkBool("finally on exception", true, r2.endsWith("(done)"));

        // ── summary ──
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void checkBool(String label, boolean expected, boolean actual) {
        if (expected == actual) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected " + expected + " but got " + actual); failed++;
        }
    }
    static void fail(String label) {
        System.out.println("FAIL: " + label + " \u2014 no exception thrown"); failed++;
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e); failed++;
    }
}
